#include <stdio.h>
#include <stdlib.h>
#define MOD 998244353
int main() {
    int N, P, M;
    scanf("%d %d %d", &N, &P, &M);
    long long dp[M+1][P];
    for (int i = 0; i <= M; i++) {
        for (int j = 0; j < P; j++) {
            dp[i][j] = 0;
        }
    }
    dp[0][0] = 1;
    for (int i = 1; i <= M; i++) {
        for (int j = 0; j < P; j++) {
            for (int k = 0; k <= 9 && k <= i; k++) {
                int idx = (j + k) % P;
                dp[i][idx] = (dp[i][idx] + dp[i-k][j]) % MOD;
            }
        }
    }
    for (int i = 0; i <= M; i++) {
        long long ans = 0;
        for (int j = 0; j < P; j++) {
            if (j % P == 0) {
                ans = (ans + dp[i][j]) % MOD;
            }
        }
        printf("%lld ", ans);
    }
    return 0;
}

